sql_query:
SELECT "Number of arms"
FROM clinical_trials
WHERE "Cancer type" = 'Gastric/GEJ';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Number of arms" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Gastric/GEJ'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_arm_category(source_value) AS "arm_category"
FROM base;
